proof_block:
// Step 1: Pull both `next_ensures` antecedents into a real `if` so we
// can call the decomposition helper on r1 and r2. Outside the `if` the
// goal is vacuous; inside it the antecedents hold, the helper unfolds
// `next_ensures` into atomic conjuncts (including the per-index
// `well_typed_events` foralls) and surfaces them as named hypotheses
// for both runs simultaneously.
if HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    && HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
{
    lemma_next_ensures_components(pre_self_, pre_netc, post1_self_, post1_netc, r1);
    lemma_next_ensures_components(pre_self_, pre_netc, post2_self_, post2_netc, r2);

    // Step 2: Re-derive the `ok` bit equality for both runs from the
    // helper's first ensures. These are direct restatements, so they
    // verify, but they put `r1.0 == post1_netc.ok()` and
    // `r2.0 == post2_netc.ok()` in scope as explicit equalities that
    // z3 can rewrite with when comparing the two `.0` components.
    assert(r1.0 == post1_netc.ok());
    assert(r2.0 == post2_netc.ok());

    // Step 3: The history conjunct, restated as a named hypothesis
    // for each run (gated on `ok || sends>0`, matching `next_ensures`).
    assert((r1.0 || (r1.1)@.sends.len() > 0)
        ==> post1_netc.history() == pre_netc.history() + (r1.1)@.event_seq());
    assert((r2.0 || (r2.1)@.sends.len() > 0)
        ==> post2_netc.history() == pre_netc.history() + (r2.1)@.event_seq());

    // Step 4: `event_seq()` is `recvs + clocks + sends`, an open spec.
    // Re-assert the unfolding on both sides so z3 has a syntactic
    // handle to compare sequence concatenations index-wise.
    assert((r1.1)@.event_seq() == (r1.1)@.recvs + (r1.1)@.clocks + (r1.1)@.sends);
    assert((r2.1)@.event_seq() == (r2.1)@.recvs + (r2.1)@.clocks + (r2.1)@.sends);

    // Step 5: Sequence extensionality bridge — for any two sequences
    // of `NetEvent`s, deep equality (`=~=`) entails structural equality
    // (`==`). z3 needs this to lift any pointwise sequence equality
    // it derives up to `Seq<NetEvent>` equality used in the
    // `EventResultsView` / `NetClientView` comparisons of `det_*_equal`.
    assert(forall|s1: Seq<NetEvent>, s2: Seq<NetEvent>| s1 =~= s2 ==> s1 == s2);

    // Step 6: Same extensionality for `History` (an alias for
    // `Seq<NetEvent>`, but spelled differently in some signatures),
    // so the `NetClientView.history` comparison goes through.
    assert(forall|h1: History, h2: History| h1 =~= h2 ==> h1 == h2);
}

helper_lemmas:
// Functional-decomposition lemma for `HostState::next_ensures`.
//
// `next_ensures` is an `open spec fn` whose body is a top-level
// conjunction (with one inner `let (ok, res) = rc;` destructuring).
// Each ensures clause below is one of those conjuncts (or one of the
// `forall` conjuncts inside the open `EventResults::well_typed_events`),
// so the body verifies purely by unfolding the two open spec fns.
//
// Calling this lemma once for each run forces every conjunct into
// z3's hypothesis context as an *atomic* fact with an explicit
// per-occurrence trigger — which is what the previous attempt was
// missing: the two `forall|i| ...` quantifiers inside
// `well_typed_events` had disjoint triggers across r1 / r2, so z3
// never simultaneously instantiated them on the same i.
proof fn lemma_next_ensures_components(
    pre_self_: HostState, pre_netc: NetClient,
    post_self_: HostState, post_netc: NetClient,
    rc: (bool, Ghost<EventResults>),
)
    requires
        HostState::next_ensures(pre_self_, pre_netc, post_self_, post_netc, rc),
    ensures
        rc.0 == post_netc.ok(),
        rc.0 ==> post_self_.invariants(&post_netc.my_end_point()),
        rc.0 ==> HostState::next(pre_self_.view(), post_self_.view(), (rc.1)@.ios),
        rc.0 ==> (rc.1)@.event_seq() == (rc.1)@.ios,
        (rc.0 || (rc.1)@.sends.len() > 0)
            ==> post_netc.history() == pre_netc.history() + (rc.1)@.event_seq(),
        (rc.1)@.well_typed_events(),
        forall|i: int| 0 <= i < (rc.1)@.recvs.len() ==>
            #[trigger] (rc.1)@.recvs[i] is Receive,
        forall|i: int| 0 <= i < (rc.1)@.clocks.len() ==>
            (#[trigger] (rc.1)@.clocks[i] is ReadClock
                || (rc.1)@.clocks[i] is TimeoutReceive),
        forall|i: int| 0 <= i < (rc.1)@.sends.len() ==>
            #[trigger] (rc.1)@.sends[i] is Send,
        (rc.1)@.clocks.len() <= 1,
        (rc.1)@.event_seq() == (rc.1)@.recvs + (rc.1)@.clocks + (rc.1)@.sends,
{
}
